[CmdletBinding()] param([Parameter(Mandatory)][string]$CliPath,[switch]$KeepReports)
$ErrorActionPreference='Stop';$cli=(Resolve-Path -LiteralPath $CliPath).Path;$root=Join-Path ([IO.Path]::GetTempPath()) ('LicenseScope-Compatibility-'+[guid]::NewGuid().ToString('N'));[IO.Directory]::CreateDirectory($root)|Out-Null
try{& $cli compatibility --json;if($LASTEXITCODE -ne 0){exit $LASTEXITCODE};& $cli audit --all --format json,csv,html --output $root --quiet;$auditExit=$LASTEXITCODE;if($auditExit -notin 0,1,2){exit $auditExit};$text=(Get-ChildItem -LiteralPath $root -File|Get-Content -Raw)-join "`n";if($text -match '[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\.[A-Za-z]{2,}|C:\\Users\\(?!<)|access.?token|refresh.?token'){throw 'Privacy scan failed'};exit 0}finally{if(-not $KeepReports -and [IO.Directory]::Exists($root)){[IO.Directory]::Delete($root,$true)}}
